  ('elementary-e0adf6cd-moex-00533', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-112-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何者是「教育科學研究」所強調的特徵？', '["主觀性", "客觀性", "歷史脈絡", "詮釋意義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:39+00:00", "source_pdf_sha1": "3d96b660454f", "answer_pdf_sha1": "46381198e246", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
